sPrefix = Trim(pPrefix); If(sPrefix @= ''); sPrefix = 'IMF'; EndIf;
sSeverity = Upper(Trim(pSeverity)); sObjectType = Trim(pObjectType); sObjectName = Trim(pObjectName); sMessage = Trim(pMessage); sRunId = Trim(pRunId);
sUseBedrock = Upper(Trim(pUseBedrock)); sBedrockProcess = Trim(pBedrockProcess); sStrictBedrock = Upper(Trim(pStrictBedrock));
nBedrockReturn = ProcessExitNormal();
sBedrockStrictError = '0';
If(sSeverity @= ''); sSeverity = 'INFO'; EndIf;
sFormattedMessage = 'IMF.EVENT|' | sSeverity | '|' | sRunId | '|' | sObjectType | '|' | sObjectName | '|' | sMessage;
If(sUseBedrock @= ''); sUseBedrock = 'N'; EndIf;
If(sBedrockProcess @= ''); sBedrockProcess = '}bedrock.server.writetomessagelog'; EndIf;
If(sStrictBedrock @= ''); sStrictBedrock = 'N'; EndIf;
If(sStrictBedrock @= 'Y'); sBedrockStrictError = '1'; EndIf;
LogOutput('INFO', sFormattedMessage);
If(sUseBedrock @= 'Y');
  If(ProcessExists(sBedrockProcess) = 1);
    nBedrockReturn = ExecuteProcess(sBedrockProcess, 'pLevel', sSeverity, 'pMessage', sFormattedMessage, 'pLogOutput', '0', 'pStrictErrorHandling', sBedrockStrictError);
    If(nBedrockReturn <> ProcessExitNormal() & sStrictBedrock @= 'Y');
      ProcessBreak;
    EndIf;
  ElseIf(sStrictBedrock @= 'Y');
    ProcessBreak;
  EndIf;
EndIf;
